<svg viewBox="0 0 700 460" xmlns="http://www.w3.org/2000/svg" style="width:100%;height:auto;background:#111113;border-radius:12px;border:1px solid rgba(255,255,255,.08);margin:20px 0">
  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">Die Zwei Gesichter von Dollar-Stablecoins — IWF-Modell WP/2026/056</text>
  <text x="20" y="50" fill="#71717a" font-size="12" font-family="sans-serif">Veröffentlicht am 11. Juli 2026 · Autor: Brandon Joel Tan</text>
  <rect x="20" y="72" width="660" height="50" rx="8" fill="#18181b" stroke="#3f3f46"/>
  <text x="350" y="93" fill="#e4e4e7" font-family="sans-serif" font-size="14" font-weight="700" text-anchor="middle">Festes / rationiertes Wechselkurssystem (offizieller Kanal begrenzt Dollarangebot)</text>
  <text x="350" y="112" fill="#71717a" font-family="sans-serif" font-size="12" text-anchor="middle">&#8594; Lücke zwischen offiziellem und informellem (Schwarzmarkt-)Kurs entsteht</text>
  <line x1="350" y1="122" x2="350" y2="150" stroke="#f7931a" stroke-width="2"/>
  <polygon points="343,150 357,150 350,162" fill="#f7931a"/>
